command:example.dev:code:
PS C:\> $OrgData = [PSCustomObject]@{
    name = 'Contoso'
}
PS C:\> New-Action1 -Item Organization -Data $OrgData

PS C:\> $Payload = [PSCustomObject]@{
    name = 'Custom object'
}
PS C:\> New-Action1 -Item RawURI -URI '/v1/custom/resource' -Data $Payload

$data = [PSCustomObject]@{
    comment = 'Managed by the infrastructure team'
}

Update-Action1 -Action Modify -Type Endpoint -Id 'endpoint-123' -Data $data

$data = [PSCustomObject]@{
    name = 'Updated object name'
}

Update-Action1 -Action Modify -Type RawURI -URI '/v1/custom/path' -Data $data
